#!/usr/bin/perl
use strict;
use warnings;
use CGI qw(:standard);
use File::Basename;

my $log_dir = '/path/to/logs';  # Set your log directory here
my $cgi = CGI->new;

print $cgi->header('text/plain');

my $filename = $cgi->param('logfile');

# Prevent path traversal
if ($filename =~ m/^\.\.|\.\.\/|\/|\\/) {
    print "Invalid log file name.";
    exit;
}

$filename = basename($filename);  # Get just the filename

